UPDATE public.questions SET
  stimulus_text = 'The most effective way to write a sentence is to use clear, concise language. However, the sentence should also be grammatically correct, which means that all parts of the sentence need to be properly constructed. For example, the sentence “The dog ran fast, and he was happy” is grammatically correct, but it is not the most effective way to write this sentence. The sentence “The dog ran quickly and happily” is both grammatically correct and clear. The sentence “The dog happily and quickly ran” is also grammatically correct, but it is awkward. Which of the following sentences is the most effective and grammatically correct?',
  question_text = 'Which of the following sentences is the most effective and grammatically correct?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The dog ran quickly, and he was happy.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The dog ran quickly and happily.","is_correct":true,"explanation":"Choice B is the most effective because it is both clear and grammatically correct. It avoids unnecessary words and phrases, and it maintains a logical order. Choice A is grammatically correct but is less effective because the inclusion of the phrase \"and he was happy\" is redundant, as the phrase \"qu. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The dog happily and quickly ran.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The dog was happily and quickly running.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'Choice B is the most effective because it is both clear and grammatically correct. It avoids unnecessary words and phrases, and it maintains a logical order. Choice A is grammatically correct but is less effective because the inclusion of the phrase "and he was happy" is redundant, as the phrase "quickly and happily" already implies that the dog was happy. Choice C is grammatically correct, but it is awkward because it places the adverbs "happily" and "quickly" before the verb "ran," making the sentence sound less natural. Choice D is grammatically correct but is also awkward because it includes the unnecessary progressive tense, "was running." The sentence "The dog ran quickly and happily" is the most effective and grammatically correct sentence because it is clear, concise, and grammatically correct. The passage states that "The most effective way to write a sentence is to use clear, concise language. However, the sentence should also be gramm…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: The dog ran quickly and happily.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":96,"opensat_domain":"Standard English Conventions","opensat_raw_id":"2d26268d","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.901Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
